#include <stdio.h>
#include <stdlib.h>
int main()
{
    // This pointer will hold the base address of the block created
    int *ptr;
    int n, i;
    // Get the number of elements for the array
    n = 5;
    printf("Enter the number of elements: %d\n", n);
    // Allocate memory using calloc
    ptr = (int*) calloc(n, sizeof(int));
    // Check if memory allocation was successful
    if (ptr == NULL) {
        printf("Memory not allocated.\n");
        exit(0);
    }
    else {
        // Memory successfully allocated
        printf("Memory successfully allocated using calloc.\n");
        // Initialize the elements of the array
        for (i = 0; i < n; ++i) {
            ptr[i] = i + 1;
        }
        // Print the elements of the array
        printf("The elements of the array are: ");
        for (i = 0; i < n; ++i) {
            printf("%d, ", ptr[i]);
        }
        // Get the new size for the array
        n = 10;
        printf("\n\nEnter the new size of the array: %d\n", n);
        // Dynamically re-allocate memory using realloc()
        ptr = (int*) realloc(ptr, n * sizeof(int));
        if (ptr == NULL) {
            printf("Reallocation Failed\n");
            exit(0);
        }
        // Memory successfully reallocated
        printf("Memory successfully re-allocated using realloc.\n");
        // Initialize the new elements of the array
        for (i = 5; i < n; ++i) {
            ptr[i] = i + 1;
        }
        // Print the updated elements of the array
        printf("The elements of the array are: ");
        for (i = 0; i < n; ++i) {
            printf("%d, ", ptr[i]);
        }
        // Free allocated memory
        free(ptr);
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#define MAX 5
int s[MAX];
int top = -1;
void push();
void pop();
void display();
int main() // Changed `void main()` to `int main()` (Standard in C)
{
    int choice;
    while (1)
    {
        printf("\nSTACK OPERATIONS\n");
        printf("1. PUSH\n");
        printf("2. POP\n");
        printf("3. DISPLAY\n");
        printf("4. EXIT\n");
        printf("Enter your choice: ");
        scanf("%d", &choice);
        switch (choice)
        {
            case 1: push();
            break;
            case 2: pop();
            break;
            case 3: display();
            break;
            case 4: exit(0);
            break;
            default: printf("Invalid Choice\n");
            break;
        }
    }
    return 0; // Added return statement for `main`
}
void push()
{
    int item;
    if (top == MAX - 1)
    {
        printf("Stack Overflow\n");
        return;
    }
    printf("Enter an element to be pushed: ");
    scanf("%d", &item);
    top = top + 1;
    s[top] = item;
}
void pop()
{
    int item;
    if (top == -1)
    {
        printf("Stack Underflow\n");
        return;
    }
    item = s[top];
    top = top - 1;
    printf("Element popped is %d\n", item);
}
void display()
{
    int i;
    if (top == -1)
    {
        printf("Stack is Empty\n");
        return;
    }
    printf("Stack elements are:\n");
    for (i = top; i >= 0; i--)
    {
        printf("| %d |\n", s[i]);
    }
}

#include <stdio.h>
#include <stdlib.h>
#define MAX 50
void insert();
void delete();
void display();
int queue_array[MAX];
int rear = -1;
int front = -1;
int main()
{
    int choice;
    while (1)
    {
        printf("\n1. Insert element to queue\n");
        printf("2. Delete element from queue\n");
        printf("3. Display all elements of queue\n");
        printf("4. Quit\n");
        printf("Enter your choice: ");
        scanf("%d", &choice);
        switch (choice)
        {
            case 1: insert();
            break;
            case 2: delete();
            break;
            case 3: display();
            break;
            case 4: exit(0);
            default: printf("Wrong choice\n");
        }
    }
    return 0;
}
void insert()
{
    int item;
    if (rear == MAX - 1)
    {
        printf("Queue Overflow\n");
        return;
    }
    if (front == -1)
        front = 0;
    printf("Insert the element in queue: ");
    scanf("%d", &item);
    rear = rear + 1;
    queue_array[rear] = item;
}
void delete()
{
    if (front == -1 || front > rear)
    {
        printf("Queue Underflow\n");
        return;
    }
    else
    {
        printf("Element deleted from queue is: %d\n", queue_array[front]);
        front = front + 1;
    }
}
void display()
{
    int i;
    if (front == -1 || front > rear)
    {
        printf("Queue is empty\n");
        return;
    }
    else
    {
        printf("Queue is: ");
        for (i = front; i <= rear; i++)
            printf("%d ", queue_array[i]);
        printf("\n");
    }
}

