#include <stdio.h>
#include <stdlib.h>
struct node {
    int data;
    struct node *lchild;
    struct node *rchild;
};
typedef struct node *NODE;
NODE root = NULL;
void insert();
void search(); // Removed (NODE root) because search() does not take an argument
void inorder(NODE root);
void preorder(NODE root);
void postorder(NODE root);
void display(NODE root, int);
void main() {
    int ch, i, n;
    for (;;) {
        printf("\n*** TREE OPERATIONS ***\n");
        printf("1: Insert node\n");
        printf("2: Inorder traversal\n");
        printf("3: Preorder traversal\n");
        printf("4: Postorder traversal\n");
        printf("5: Display\n");
        printf("6: Search\n");
        printf("7: Exit\n");
        printf("*************************\n");
        printf("\nEnter your choice: ");
        scanf("%d", &ch);
        switch (ch) {
            case 1:
                printf("Enter the number of elements: ");
                scanf("%d", &n);
                for (i = 0; i < n; i++)
                    insert();
                break;
            case 2:
                if (root == NULL)
                    printf("Empty tree\n");
                else {
                    printf("Inorder traversal: ");
                    inorder(root);
                    printf("\n");
                }
                break;
            case 3:
                if (root == NULL)
                    printf("Empty tree\n");
                else {
                    printf("Preorder traversal: ");
                    preorder(root);
                    printf("\n");
                }
                break;
            case 4:
                if (root == NULL)
                    printf("Empty tree\n");
                else {
                    printf("Postorder traversal: ");
                    postorder(root);
                    printf("\n");
                }
                break;
            case 5:
                if (root == NULL)
                    printf("Empty tree\n");
                else {
                    printf("The tree is:\n");
                    display(root, 1);
                    printf("\n");
                }
                break;
            case 6:
                search();
                break;
            case 7:
                exit(0);
            default:
                printf("Invalid choice\n");
                break;
        }
    }
}
void insert() {
    NODE newnode, prev, curr;
    newnode = (NODE)malloc(sizeof(struct node));
    printf("Enter the element to be inserted in the tree: ");
    scanf("%d", &newnode->data);
    newnode->lchild = newnode->rchild = NULL;
    if (root == NULL) {
        root = newnode;
        return;
    }
    prev = NULL;
    curr = root;
    while (curr != NULL) {
        if (curr->data == newnode->data) {
            printf("Duplicate is not allowed\n");
            free(newnode);
            return;
        }
        prev = curr;
        if (newnode->data < curr->data)
            curr = curr->lchild;
        else
            curr = curr->rchild;
    }
    if (newnode->data < prev->data)
        prev->lchild = newnode;
    else
        prev->rchild = newnode;
}
void search() {
    int key;
    NODE curr;
    printf("Enter the element to be searched: ");
    scanf("%d", &key);
    if (root == NULL) {
        printf("Tree is empty\n");
        return;
    }
    curr = root;
    while (curr != NULL) {
        if (curr->data == key) {
            printf("Number found\n");
            return;
        }
        if (key < curr->data)
            curr = curr->lchild;
        else
            curr = curr->rchild;
    }
    printf("Number not found\n");
}
void inorder(NODE root) {
    if (root != NULL) {
        inorder(root->lchild);
        printf("%4d", root->data);
        inorder(root->rchild);
    }
}
void preorder(NODE root) {
    if (root != NULL) {
        printf("%4d", root->data);
        preorder(root->lchild);
        preorder(root->rchild);
    }
}
void postorder(NODE root) {
    if (root != NULL) {
        postorder(root->lchild);
        postorder(root->rchild);
        printf("%4d", root->data);
    }
}
void display(NODE root, int level) {
    int i;
    if (root) {
        display(root->rchild, level + 1);
        printf("\n");
        for (i = 0; i < level; i++)
            printf("\t");
        printf("%d", root->data);
        display(root->lchild, level + 1);
    }
}

#include <stdio.h>
#include <stdlib.h>
#define MAX 100
int create(int);
void linear_prob(int[], int, int);
void display(int[]);
int main() {
    int a[MAX], num, key, i;
    int ans = 1;
    printf("Collision handling by linear probing:\n");
    for (i = 0; i < MAX; i++)
        a[i] = -1;
    do {
        printf("\n Enter the data: ");
        scanf("%d", &num);
        key = create(num);
        linear_prob(a, key, num);
        printf("\n Do you wish to continue ? (1/0): ");
        scanf("%d", &ans);
    } while (ans);
    display(a);
    return 0;
}
int create(int num) {
    int key;
    key = num % 97;
    return key;
}
void linear_prob(int a[MAX], int key, int num) {
    int flag, i, count = 0;
    flag = 0;
    if (a[key] == -1)
        a[key] = num;
    else {
        printf("\n Collision Detected...!!!\n");
        i = 0;
        while (i < MAX) {
            if (a[i] != -1)
                count++;
            i++;
        }
        printf("Collision avoided successfully using LINEAR PROBING\n");
        if (count == MAX) {
            printf("\n Hash table is full");
            display(a);
            exit(1);
        }
        for (i = key + 1; i < MAX; i++)
            if (a[i] == -1) {
                a[i] = num;
                flag = 1;
                break;
            }
        i = 0;
        while ((i < key) && (flag == 0)) {
            if (a[i] == -1) {
                a[i] = num;
                flag = 1;
                break;
            }
            i++;
        }
    }
}
void display(int a[MAX]) {
    int i, choice;
    while (1) {
        printf("\n\n 1.Display ALL\n 2.Filtered Display\n 3.Exit\n");
        scanf("%d", &choice);
        switch (choice) {
            case 1:
                printf("\n The hash table is:\n");
                for (i = 0; i < MAX; i++)
                    printf("\n %d -> %d", i, a[i]);
                break;
            case 2:
                printf("\n The hash table is:\n");
                for (i = 0; i < MAX; i++)
                    if (a[i] != -1)
                        printf("\n %d -> %d", i, a[i]);
                break;
            case 3:
                exit(0);
            default:
                printf("Invalid choice. Try again.\n");
        }
    }
}
